import { cn } from '@/utils/cn';
import { cva, type VariantProps } from 'class-variance-authority';
import { Component, Match, mergeProps, splitProps, Switch } from 'solid-js';
import { ButtonProps } from './button.types';

type Opacity = {
  from: string;
  to: string;
};
export function rippleAnimate(
  target: HTMLButtonElement,
  duration: number = 300,
  opacity: Opacity = { from: '20%', to: '10%' },
) {
  if (!target) return;
  target.animate(
    [
      { boxShadow: `0 0 0 0 rgba(from var(--btn-color) r g b / ${opacity.from})` },
      { boxShadow: `0 0 0 6px rgba(from var(--btn-color) r g b / ${opacity.to})` },
    ],
    {
      duration,
      easing: 'linear',
    },
  );
}
const variants = cva('', {
  variants: {
    size: {
      '4xs': 'bt-4xs',
      '3xs': 'bt-3xs',
      '2xs': 'bt-2xs',
      xs: 'bt-xs',
      sm: 'bt-sm',
      md: 'bt-md',
      lg: 'bt-lg',
      xl: 'bt-xl',
      '2xl': 'bt-2xl',
      '3xl': 'bt-3xl',
      '4xl': 'bt-4xl',
    },
    color: {
      neutral: 'btn-neutral',
      primary: 'btn-primary',
      secondary: 'btn-secondary',
      accent: 'btn-accent',
      info: 'btn-info',
      success: 'btn-success',
      warning: 'btn-warning',
      error: 'btn-error',
    },
    variant: {
      default: 'btn-default',
      simple: 'btn-default border-transparent',
      solid: '',
      outline: 'btn-outline',
      dashed: 'btn-dash',
      soft: 'btn-soft',
      text: 'btn-ghost',
      link: 'btn-link',
    },
    shape: {
      circle: 'aspect-square rounded-full',
      square: 'aspect-square',
    },
    loadingType: {
      dots: 'loading-dots',
      ring: 'loading-ring',
      ball: 'loading-ball',
      bars: 'loading-bars',
      infinity: 'loading-infinity',
      spinner: 'loading-spinner',
    },
  },
});
export type ButtonVariantsProps = VariantProps<typeof variants>;

export const Button: Component<ButtonProps> = props => {
  const merge = mergeProps(
    {
      size: 'sm' as const,
      disabled: false,
      loading: false,
      color: 'secondary' as const,
      class: void 0,
      iconPlacement: 'start',
      loadingOptions: {
        type: 'spinner' as const,
        size: 20,
      },
      animate: 'ripple' as const,
    },
    props,
  );
  const isShape = merge.shape === 'square' || merge.shape === 'circle';
  const [p, nativeProps] = splitProps(merge, [
    'size',
    'iconPlacement',
    'loading',
    'variant',
    'color',
    'shape',
    'icon',
    'children',
    'class',
    'disabled',
    'onClick',
    'loadingOptions',
    'animate',
  ]);
  const handleClick = (e: MouseEvent) => {
    p.onClick?.(e);
    if (p.animate === 'ripple') {
      const target = e.currentTarget as HTMLButtonElement;
      switch (p.variant) {
        case 'default':
        case 'simple':
        case 'link':
          return rippleAnimate(target, 300, { from: '8%', to: '2%' });
        default:
          return rippleAnimate(target);
      }
    }
  };
  return (
    <button
      {...nativeProps}
      class={cn(
        'sbt',
        variants({ size: p.size, color: p.color, variant: p.variant, shape: p.shape }),
        !isShape && p.icon && (p.iconPlacement === 'start' ? 'flex-row' : 'flex-row-reverse'),
        p.icon && '[&_svg]:shrink-0',
        p.animate !== 'translate' && 'active:translate-none',
        p.class,
      )}
      {...(p.shape && { 'data-shape': p.shape })}
      onClick={handleClick}
      disabled={p.disabled || p.loading}
    >
      <Switch>
        <Match when={p.loading}>
          <span
            class={cn('loading shrink-0', variants({ loadingType: p.loadingOptions?.type }))}
            style={{ width: `${p.loadingOptions?.size}px` }}
          ></span>
        </Match>

        <Match when={!p.loading && p.icon}>{p.icon! as Element}</Match>
      </Switch>
      {!isShape && p.children && <span class="mb-px">{p.children}</span>}
    </button>
  );
};
